INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7, 1, -409.0, 190801, "2030/12/17 14:59:59", "カリン", 0.0, 0, 1, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 0, 31001, "2019/10/31 12:00:00", 0.0, 31);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (8, 1, -409.0, 190801, "2030/12/17 14:59:59", "カリン", 0.0, 0, 1, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 0, 31002, "2019/10/31 12:00:00", 0.0, 31);
