INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 2, -458.0, 105801, "2030/12/17 14:59:59", "ペコリーヌ", 0.0, 0, 1, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 0, 38002, "2015/12/17 15:00:00", 6.5, 38);
