INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 1, -430.0, 190801, "2030/12/17 14:59:59", "カリン", 0.0, 0, 1, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 0, 40001, "2015/12/17 15:00:00", 0.0, 40);
