INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 105801, "2030/12/17 14:59:59", "ペコリーヌ", 0.0, 0, 1, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 0, 41002, "2015/12/17 15:00:00", 0.0, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 106001, "2030/12/17 14:59:59", "キャル", 0.0, 0, 1, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 0, 41003, "2015/12/17 15:00:00", 0.0, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 105901, "2030/12/17 14:59:59", "コッコロ", 0.0, 0, 1, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 0, 41004, "2015/12/17 15:00:00", 0.0, 41);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -416.5, 105901, "2030/12/17 14:59:59", "コッコロ", 0.0, 0, 1, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 0, 42001, "2015/12/17 15:00:00", 0.0, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -416.5, 106401, "2030/12/17 14:59:59", "シェフィ", 0.0, 0, 1, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 2104010, 42002, "2015/12/17 15:00:00", 0.0, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -416.5, 105801, "2030/12/17 14:59:59", "ペコリーヌ", 0.0, 0, 1, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 0, 42003, "2015/12/17 15:00:00", 0.0, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -416.5, 106001, "2030/12/17 14:59:59", "キャル", 0.0, 0, 1, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 0, 42004, "2015/12/17 15:00:00", 0.0, 42);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 105801, "2030/12/17 14:59:59", "ペコリーヌ", 0.0, 0, 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 0, 43001, "2015/12/17 15:00:00", 0.0, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 105901, "2030/12/17 14:59:59", "コッコロ", 0.0, 0, 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 0, 43002, "2015/12/17 15:00:00", 0.0, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -363.0, 106001, "2030/12/17 14:59:59", "キャル", 0.0, 0, 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 0, 43003, "2015/12/17 15:00:00", 0.0, 43);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -416.5, 123001, "2030/12/17 14:59:59", "アメス", 0.0, 0, 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 0, 43004, "2015/12/17 15:00:00", 0.0, 44);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2, 1, -416.5, 123001, "2030/12/17 14:59:59", "アメス", 0.0, 0, 1, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 0, 43005, "2015/12/17 15:00:00", 0.0, 44);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (3, 2, -416.5, 123001, "2030/12/17 14:59:59", "アメス", 0.0, 0, 1, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 0, 43006, "2015/12/17 15:00:00", 5.79, 45);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 1, -371.5, 123001, "2030/12/17 14:59:59", "アメス", 0.0, 0, 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 0, 46001, "2015/12/17 15:00:00", 0.0, 46);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2, -416.5, 104901, "2030/12/17 14:59:59", "シズル", 0.0, 0, 2, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 0, 47001, "2015/12/17 15:00:00", 0.0, 47);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (1, 2, -416.5, 101101, "2030/12/17 14:59:59", "リノ", 0.0, 0, 1, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 0, 47002, "2015/12/17 15:00:00", 9.32, 47);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, 2, -470.0, 104901, "2030/12/17 14:59:59", "シズル", 0.0, 0, 2, "", 0, 48001, "2015/12/17 15:00:00", 0.0, 48);
